AND record_date BETWEEN #{startDate, jdbcType=DATE} AND #{endDate, jdbcType=DATE}
ORDER BY record_date DESC, create_time DESC

SELECT IFNULL(SUM(amount), 0.00)
FROM t_finance
WHERE user_id = #{userId, jdbcType=BIGINT}

    AND record_type = #{recordType, jdbcType=INTEGER}


    AND record_date BETWEEN #{startDate, jdbcType=DATE} AND #{endDate, jdbcType=DATE}

SELECT category_id AS categoryId, category_name AS categoryName, IFNULL(SUM(amount), 0.00) AS totalAmount, COUNT(*) AS recordCount FROM t_finance WHERE user_id = #{userId, jdbcType=BIGINT}
AND record_type = #{recordType, jdbcType=INTEGER}
AND record_date BETWEEN #{startDate, jdbcType=DATE} AND #{endDate, jdbcType=DATE}
GROUP BY category_id, category_name ORDER BY totalAmount DESC

SELECT

FROM t_finance
WHERE user_id = #{userId, jdbcType=BIGINT}
ORDER BY create_time DESC
LIMIT #{limit, jdbcType=INTEGER}

SELECT

FROM t_finance

    AND user_id = #{userId, jdbcType=BIGINT}
    AND record_type = #{recordType, jdbcType=INTEGER}
    AND category_id = #{categoryId, jdbcType=BIGINT}
    
        AND record_date BETWEEN #{startDate, jdbcType=DATE} AND #{endDate, jdbcType=DATE}
    
    
        AND (
        category_name LIKE CONCAT('%', #{keyword, jdbcType=VARCHAR}, '%')
        OR remark LIKE CONCAT('%', #{keyword, jdbcType=VARCHAR}, '%')
        OR invoice_no LIKE CONCAT('%', #{keyword, jdbcType=VARCHAR}, '%')
        )
    

ORDER BY record_date DESC, create_time DESC
LIMIT #{startIndex, jdbcType=INTEGER}, #{pageSize, jdbcType=INTEGER}

